export const ChatCitationSource = {
  "srd-2014": "srd-2014",
  "srd-2024": "srd-2024",
  campaign: "campaign",
  homebrew: "homebrew",
  character: "character",
} as const;

/**
 * DM-only — which authored field a campaign chunk came from.
 */
export type ChatCitationSourceField =
  (typeof ChatCitationSourceField)[keyof typeof ChatCitationSourceField];

export const ChatCitationSourceField = {
  public_md: "public_md",
  secret_md: "secret_md",
  dm_notes: "dm_notes",
} as const;

export interface ChatCitation {
  source: ChatCitationSource;
  entityKind: string;
  entityName: string;
  chunkId: number;
  /** DM-only — which authored field a campaign chunk came from. */
  sourceField?: ChatCitationSourceField;
  /** @nullable */
  sourceUrl?: string | null;
}

export type ChatResponseEdition =
  (typeof ChatResponseEdition)[keyof typeof ChatResponseEdition];

export const ChatResponseEdition = {
  NUMBER_2014: "2014",
  NUMBER_2024: "2024",
} as const;

export interface ChatResponse {
  answer: string;
  citations: ChatCitation[];
  edition: ChatResponseEdition;
  /** Thread ID this message belongs to. Send it back on follow-ups to keep the conversation going. */
  conversationId: number;
}

export interface ChatThread {
  id: number;
  title: string;
  /**
   * Character the user has chosen to speak as on this thread, if any.
   * @nullable
   */
  speakingAsCharacterId?: number | null;
  createdAt: string;
  updatedAt: string;
}

export interface UpdateChatThreadBody {
  /**
   * @minLength 1
   * @maxLength 200
   */
  title?: string;
  /**
   * Set the character the user is speaking as on this thread, or null to clear.
   * @nullable
   */
  speakingAsCharacterId?: number | null;
}

export interface SpeakableCharacter {
  id: number;
  name: string;
  race: string;
  class: string;
  level: number;
  /** @nullable */
  portraitUrl?: string | null;
  ownerUserId: string;
  ownerDisplayName: string;
}

export type ChatThreadMessageRole =
  (typeof ChatThreadMessageRole)[keyof typeof ChatThreadMessageRole];

export const ChatThreadMessageRole = {
  user: "user",
  assistant: "assistant",
} as const;

export interface ChatThreadMessage {
  id: number;
  role: ChatThreadMessageRole;
  content: string;
  createdAt: string;
}

export interface ChatThreadDetail {
  thread: ChatThread;
  messages: ChatThreadMessage[];
}

export type SearchRulesParams = {
  /**
   * @minLength 1
   */
  q: string;
  edition?: SearchRulesEdition;
  kind?: string;
  /**
   * @minimum 1
   * @maximum 50
   */
  limit?: number;
};

export type SearchRulesEdition =
  (typeof SearchRulesEdition)[keyof typeof SearchRulesEdition];

export const SearchRulesEdition = {
  NUMBER_2014: "2014",
  NUMBER_2024: "2024",
} as const;

export type GetRuleParams = {
  edition?: GetRuleEdition;
};

export type GetRuleEdition =
  (typeof GetRuleEdition)[keyof typeof GetRuleEdition];

export const GetRuleEdition = {
  NUMBER_2014: "2014",
  NUMBER_2024: "2024",
} as const;

export type DeleteEventParams = {
  series?: boolean;
};

export type DeleteEvent200 = {
  deleted: number;
};

export type ListEntitiesParams = {
  kind?: EntityKind;
};

export type CreateHouseRulesShareTokenBody = {
  /** When true, replace any existing token with a freshly generated one. */
  rotate?: boolean;
};
